 * - Call query_search_books_by_criteria with different filters
 * - Verify results match criteria
 */
TEST(sqlite, query_search_books_by_criteria) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Cleanup
  auto conn = sqlite::connect("test_db.sqlite").value();
  drop<Book>(conn);

  // 1. Create Book table and insert varied data
  // Table creation is handled inside the function or here
  create_table<Book>(conn);

  std::vector<Book> books = {
      {1, "The Great Gatsby", "F. Scott Fitzgerald", 1925, "Classic", 10.0},
      {2, "1984", "George Orwell", 1949, "Dystopian", 15.0},
      {3, "Brave New World", "Aldous Huxley", 1932, "Dystopian", 12.0},
      {4, "The Hobbit", "J.R.R. Tolkien", 1937, "Fantasy", 20.0},
      {5, "Harry Potter", "J.K. Rowling", 1997, "Fantasy", 25.0}
  };
  insert(conn, books);

  // 2. Test Cases

  // Case 1: Title keyword only ("Great")
  BookFilters f1{.title_keyword = "Great"};
  auto r1 = query_search_books_by_criteria(f1);
  EXPECT_EQ(r1.size(), 1);
  EXPECT_EQ(r1[0].title, "The Great Gatsby");

  // Case 2: Genre "Dystopian" and Max Price 14.0
  BookFilters f2{.genre = "Dystopian", .max_price = 14.0};
  auto r2 = query_search_books_by_criteria(f2);
  EXPECT_EQ(r2.size(), 1);
  EXPECT_EQ(r2[0].title, "Brave New World"); // 1984 is 15.0 > 14.0

  // Case 3: Min Year 1950
  BookFilters f3{.min_year = 1950};
  auto r3 = query_search_books_by_criteria(f3);
  EXPECT_EQ(r3.size(), 1);
  EXPECT_EQ(r3[0].title, "Harry Potter"); // 1997

  // Case 4: No filters (should return all)
  BookFilters f4{};
  auto r4 = query_search_books_by_criteria(f4);
  EXPECT_EQ(r4.size(), 5);

  // Case 5: All filters
  // Keyword "H", Min Year 1930, Genre "Fantasy", Max Price 30.0
  BookFilters f5{.title_keyword = "H", .min_year = 1930, .genre = "Fantasy", .max_price = 30.0};
  auto r5 = query_search_books_by_criteria(f5);
  // Matches: Hobbit (1937, Fantasy, 20.0), Harry Potter (1997, Fantasy, 25.0)
  EXPECT_EQ(r5.size(), 2);
}

