```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace cascade_delete_demo {

struct Parent {
  sqlgen::PrimaryKey<int> parent_id;
  std::string name;
};

struct Child {
  sqlgen::PrimaryKey<int> child_id;
  sqlgen::ForeignKey<int, Parent, "parent_id"> parent_id;
  std::string note;
};

/**
 * Demonstrates cascade delete behavior in SQLite using foreign key constraints.
 * Returns: bool.
 */
bool cascade_delete_demo() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // 1. Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false;
  }
  auto conn = conn_result.value();

  // 2. Drop existing tables if they exist
  auto drop_parent = drop<Parent> | if_exists;
  auto drop_child = drop<Child> | if_exists;

  auto drop_result1 = drop_parent(conn);
  auto drop_result2 = drop_child(conn);
  if (!drop_result1 || !drop_result2) {
    return false;
  }

  // 3. Create the tables
  auto create_parent = create_table<Parent>;
  auto create_child = create_table<Child>;

  auto create_result1 = create_parent(conn);
  auto create_result2 = create_child(conn);
  if (!create_result1 || !create_result2) {
    return false;
  }

  // 4. Insert sample data
  Parent parent{1, "Test Parent"};
  Child child1{1, 1, "Child 1 note"};
  Child child2{2, 1, "Child 2 note"};

  std::vector<Parent> parents{parent};
  std::vector<Child> children{child1, child2};

  auto insert_parent_result = insert(parents)(conn);
  auto insert_child_result = insert(children)(conn);
  if (!insert_parent_result || !insert_child_result) {
    return false;
  }

  // 5. Delete a parent record
  auto delete_result = delete_from<Parent>(where("parent_id"_c == 1))(conn);
  if (!delete_result) {
    return false;
  }

  // 6. Verify if child records were deleted
  auto verify_children = read<std::vector<Child>>(where("parent_id"_c == 1))(conn);
  if (!verify_children) {
    return false;
  }

  // 7. Return true if no children found (cascade delete worked), false otherwise
  return verify_children.value().empty();
}

}  // namespace cascade_delete_demo
