bool update_set_operations() {
  try {
    // 1. Connect to the database
    auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
    if (!conn_result) {
      return false;
    }
    auto connection = conn_result.value();

    // 2. Create the Account table
    const char* create_table_sql = R"(
      CREATE TABLE Account (
        account_id INTEGER PRIMARY KEY,
        balance REAL NOT NULL,
        status TEXT NOT NULL
      )
    )";

    auto execute_result = connection->execute(create_table_sql);
    if (!execute_result) {
      return false;
    }

    // 3. Insert initial data using sqlgen::write
    std::vector<Account> initial_data = {
      {1, 1000.0, "active"},
      {2, 500.0, "pending"},
      {3, 750.0, "active"}
    };

    auto write_result = sqlgen::write(initial_data)(*connection);
    if (!write_result) {
      return false;
    }

    // 4. Construct update statement with set operations
    using namespace sqlgen::literals;

    auto update_stmt = sqlgen::update<Account>(
      "balance"_c.set(1500.0),
      "status"_c.set("updated")
    ).where("account_id"_c == 1);

    // 5. Execute the update statement
    auto update_result = update_stmt(*connection);
    if (!update_result) {
      return false;
    }

    // 6. Read the updated data to verify changes
    auto read_result = sqlgen::read<std::vector<Account>>(*connection);
    if (!read_result) {
