  std::optional<std::string> department_name;
  std::optional<std::string> first_name;
  std::optional<std::string> last_name;
  std::optional<double> salary;
};

struct JoinAnalysis {
  std::vector<JoinResult> inner_join_results;
  std::vector<JoinResult> left_join_results;
  std::vector<JoinResult> right_join_results;
  std::vector<JoinResult> full_join_results;
};

JoinAnalysis analyze_department_employees_impl(const std::vector<Department>& depts, const std::vector<Employee>& emps) {
  using namespace sqlgen::literals;

  // 1. Create in-memory SQLite database connection
  auto conn = sqlgen::sqlite::connect(":memory:");

  // 2. Create tables and insert data using sqlgen::write()
  conn.write(sqlgen::write(depts)).value();
  conn.write(sqlgen::write(emps)).value();

  // Helper function to execute queries and map results
  auto execute_query = [&conn](auto query) {
    return query(conn).transform([](auto&& results) {
      return std::move(results);
    }).value();
  };

  // 3. Perform INNER JOIN
  auto inner_query = sqlgen::select_from<Department, "d">(
      "department_name"_t1 | sqlgen::as<"department_name">,
      "first_name"_t2 | sqlgen::as<"first_name">,
      "last_name"_t2 | sqlgen::as<"last_name">,
      "salary"_t2 | sqlgen::as<"salary">
    ) | sqlgen::inner_join<Employee, "e">("department_id"_t1 == "department_id"_t2);

  // 4. Perform LEFT JOIN
  auto left_query = sqlgen::select_from<Employee, "e">(
      "department_name"_t1 | sqlgen::as<"department_name">,
      "first_name"_t2 | sqlgen::as<"first_name">,
      "last_name"_t2 | sqlgen::as<"last_name">,
      "salary"_t2 | sqlgen::as<"salary">
    ) | sqlgen::left_join<Department, "d">("department_id"_t2 == "department_id"_t1);

  // 5. Perform RIGHT JOIN
  auto right_query = sqlgen::select_from<Employee, "e">(
      "department_name"_t1 | sqlgen::as<"department_name">,
      "first_name"_t2 | sqlgen::as<"first_name">,
      "last_name"_t2 | sqlgen::as<"last_name">,
      "salary"_t2 | sqlgen::as<"salary">
    ) | sqlgen::right_join<Department, "d">("department_id"_t2 == "department_id"_t1);

  // 6. Perform FULL JOIN
  auto full_query = sqlgen::select_from<Employee, "e">(
      "department_name"_t1 | sqlgen::as<"department_name">,
      "first_name"_t2 | sqlgen::as<"first_name">,
      "last_name"_t2 | sqlgen::as<"last_name">,
      "salary"_t2 | sqlgen::as<"salary">
    ) | sqlgen::full_join<Department, "d">("department_id"_t2 == "department_id"_t1);

  // 7. Execute queries and map results to JoinResult structure
  auto map_to_join_result = [](auto&& range) -> std::vector<JoinResult> {
    std::vector<JoinResult> results;
    for (auto&& row : range) {
      results.push_back(JoinResult{
        std::get<0>(row).has_value() ? std::get<0>(row).value() : std::nullopt,
        std::get<1>(row).has_value() ? std::get<1>(row).value() : std::nullopt,
        std::get<2>(row).has_value() ? std::get<2>(row).value() : std::nullopt,
        std::get<3>(row).has_value() ? std::get<3>(row).value() : std::nullopt
      });
    }
    return results;
  };

  // Execute all queries
  auto inner_range = execute_query(inner_query | sqlgen::to<std::vector<std::tuple<std::optional<std::string>, std::optional<std::string>, std::optional<std::string>, std::optional<double>>>>);
  auto left_range = execute_query(left_query | sqlgen::to<std::vector<std::tuple<std::optional<std::string>, std::optional<std::string>, std::optional<std::string>, std::optional<double>>>>);
  auto right_range = execute_query(right_query | sqlgen::to<std::vector<std::tuple<std::optional<std::string>, std::optional<std::string>, std::optional<std::string>, std::optional<double>>>>);
  auto full_range = execute_query(full_query | sqlgen::to<std::vector<std::tuple<std::optional<std::string>, std::optional<std::string>, std::optional<std::string>, std::optional<double>>>>);

  // Map results
  JoinAnalysis analysis;
  analysis.inner_join_results = map_to_join_result(inner_range);
  analysis.left_join_results = map_to_join_result(left_range);
  analysis.right_join_results = map_to_join_result(right_range);
  analysis.full_join_results = map_to_join_result(full_range);

  return analysis;
}

}  // namespace analyze_department_employees
